import heapq

class Solution:
    def nthUglyNumber(self, n: int) -> int:
        if n == 1:
            return 1

        heap = [1]
        seen = {1}

        primes = [2, 3, 5]

        ugly_number = 0
        for _ in range(n):
            ugly_number = heapq.heappop(heap)

            for p in primes:
                next_ugly = ugly_number * p
                if next_ugly not in seen:
                    seen.add(next_ugly)
                    heapq.heappush(heap, next_ugly)

        return ugly_number
